import React, { useState } from 'react';
import { Search, Globe, ChevronRight, MessageSquare, Info, Shield, Filter, TrendingUp, ExternalLink, Sparkles } from 'lucide-react';
import { SafetyMode, SearchResult } from '../types';
import { searchAI } from '../services/gemini';

interface BrowserViewProps {
  safetyMode: SafetyMode;
}

const BrowserView: React.FC<BrowserViewProps> = ({ safetyMode }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  // Track grounding sources from Google Search
  const [sources, setSources] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setIsLoading(true);
    setAiAnalysis(null);
    setSources([]);
    try {
      // Simulated aggregation of search results
      const mockResults: SearchResult[] = [
        { 
          title: "Premium AI Solutions for Enterprise", 
          url: "https://sponsored.ai/enterprise", 
          snippet: "Scale your business with cutting-edge MetaAI integration. Best-in-class performance and security.",
          isAd: true 
        },
        { 
          title: `${query} - Wikipedia`, 
          url: `https://en.wikipedia.org/wiki/${query.replace(/\s+/g, '_')}`, 
          snippet: `Exploring the historical and modern implications of ${query} in the context of contemporary society.` 
        },
        { 
          title: `The Future of ${query}: Expert Opinions`, 
          url: "https://tech-insights.com/ai-future", 
          snippet: "Top industry analysts weigh in on what's next for this transformative field." 
        }
      ];
      setResults(mockResults);

      const aiRes = await searchAI(query);
      setAiAnalysis(aiRes.text);
      // Store grounding sources
      setSources(aiRes.sources);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="p-4 md:p-8 max-w-6xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Search Bar Landing */}
      {!results.length && !isLoading && (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
          <div className="w-24 h-24 bg-gradient-to-tr from-blue-600 to-indigo-600 rounded-3xl shadow-2xl shadow-blue-500/20 mb-8 flex items-center justify-center">
            <Globe className="w-12 h-12 text-white" />
          </div>
          <h1 className="text-4xl md:text-5xl font-black text-white mb-4 tracking-tight">Hyper Browser OS</h1>
          <p className="text-zinc-400 text-lg mb-8 max-w-lg">The world's most powerful AI-integrated browser with multi-engine search and native automation.</p>

          <form onSubmit={handleSearch} className="w-full max-w-2xl relative group">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 w-6 h-6 text-zinc-500 group-focus-within:text-blue-500 transition-colors" />
            <input 
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Search anything with AI Grounding..."
              className="w-full bg-zinc-900 border border-zinc-800 rounded-2xl pl-14 pr-32 py-5 text-xl text-white outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 transition-all shadow-xl"
            />
            <button 
              type="submit"
              className="absolute right-3 top-3 bottom-3 px-6 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold transition-all transform hover:scale-105"
            >
              Search
            </button>
          </form>

          <div className="flex items-center space-x-6 mt-8 text-zinc-500">
            <span className="flex items-center space-x-1"><Shield className="w-4 h-4" /> <span>Private</span></span>
            <span className="flex items-center space-x-1"><Filter className="w-4 h-4" /> <span>Ad-Free</span></span>
            <span className="flex items-center space-x-1"><TrendingUp className="w-4 h-4" /> <span>Real-time</span></span>
          </div>
        </div>
      )}

      {/* Results Page */}
      {(isLoading || results.length > 0) && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          {/* Main Results */}
          <div className="lg:col-span-7 space-y-6">
            <form onSubmit={handleSearch} className="relative group mb-8">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
              <input 
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full bg-zinc-900 border border-zinc-800 rounded-xl pl-11 pr-4 py-3 text-white outline-none focus:border-blue-500 transition-all"
              />
            </form>

            {isLoading ? (
              <div className="space-y-6">
                {[1, 2, 3].map(i => (
                  <div key={i} className="animate-pulse space-y-3">
                    <div className="h-4 bg-zinc-800 rounded w-1/4" />
                    <div className="h-6 bg-zinc-800 rounded w-3/4" />
                    <div className="h-4 bg-zinc-800 rounded w-1/2" />
                  </div>
                ))}
              </div>
            ) : (
              results.map((res, idx) => (
                <div key={idx} className={`p-5 rounded-2xl border transition-all ${res.isAd ? 'bg-blue-500/5 border-blue-500/20' : 'bg-zinc-900/50 border-zinc-800 hover:border-zinc-700'}`}>
                  {res.isAd && <span className="text-[10px] font-bold text-blue-500 uppercase mb-2 block">Sponsored</span>}
                  <a href={res.url} target="_blank" className="group">
                    <h3 className="text-xl font-bold text-blue-400 group-hover:underline mb-1 flex items-center">
                      {res.title} <ExternalLink className="w-3 h-3 ml-2 opacity-0 group-hover:opacity-100 transition-opacity" />
                    </h3>
                  </a>
                  <p className="text-zinc-500 text-sm mb-3 truncate">{res.url}</p>
                  <p className="text-zinc-300 leading-relaxed">{res.snippet}</p>
                </div>
              ))
            )}
          </div>

          {/* AI Panel */}
          <div className="lg:col-span-5">
            <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6 sticky top-8 shadow-xl">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center space-x-2">
                  <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center">
                    <Sparkles className="w-4 h-4 text-white" />
                  </div>
                  <span className="font-bold text-white uppercase tracking-wider text-xs">AI Knowledge Pane</span>
                </div>
                <div className="px-2 py-1 bg-zinc-800 rounded text-[10px] text-zinc-500 font-bold uppercase">MetaAI Pro</div>
              </div>

              {isLoading ? (
                <div className="space-y-4">
                  <div className="h-4 bg-zinc-800 rounded animate-pulse" />
                  <div className="h-4 bg-zinc-800 rounded animate-pulse w-5/6" />
                  <div className="h-4 bg-zinc-800 rounded animate-pulse w-4/6" />
                  <div className="h-32 bg-zinc-800 rounded animate-pulse" />
                </div>
              ) : (
                <div className="space-y-6">
                  {aiAnalysis ? (
                    <>
                      <div className="prose prose-invert prose-sm">
                        <p className="text-zinc-200 leading-relaxed whitespace-pre-wrap">{aiAnalysis}</p>
                      </div>

                      {/* Grounding Sources - Mandatory as per Google GenAI guidelines */}
                      {sources.length > 0 && (
                        <div className="pt-6 border-t border-zinc-800">
                          <h4 className="text-xs font-bold text-zinc-500 uppercase mb-4">Sources</h4>
                          <div className="space-y-2">
                            {sources.map((source, i) => {
                              const uri = source.web?.uri || source.maps?.uri;
                              const title = source.web?.title || source.maps?.title || 'Source';
                              if (!uri) return null;
                              return (
                                <a 
                                  key={i} 
                                  href={uri} 
                                  target="_blank" 
                                  rel="noopener noreferrer"
                                  className="flex items-center space-x-2 text-xs text-blue-400 hover:underline truncate"
                                >
                                  <ExternalLink className="w-3 h-3 shrink-0" />
                                  <span>{title}</span>
                                </a>
                              );
                            })}
                          </div>
                        </div>
                      )}

                      <div className="pt-6 border-t border-zinc-800">
                        <h4 className="text-xs font-bold text-zinc-500 uppercase mb-4">Quick Actions</h4>
                        <div className="grid grid-cols-2 gap-2">
                          <QuickAction icon={<MessageSquare className="w-4 h-4" />} label="Ask WH?" />
                          <QuickAction icon={<Info className="w-4 h-4" />} label="Summarize" />
                        </div>
                      </div>
                    </>
                  ) : (
                    <div className="text-center py-12">
                      <Sparkles className="w-12 h-12 text-zinc-800 mx-auto mb-4" />
                      <p className="text-zinc-500 text-sm">Enter a query to see AI insights</p>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const QuickAction: React.FC<{ icon: React.ReactNode; label: string }> = ({ icon, label }) => (
  <button className="flex items-center space-x-2 px-3 py-2 bg-zinc-800 hover:bg-zinc-700 rounded-lg text-sm text-zinc-300 transition-colors">
    {icon}
    <span>{label}</span>
  </button>
);

export default BrowserView;

import React, { useState, useRef } from 'react';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Video, 
  FileText, 
  Layers, 
  Download, 
  RefreshCw,
  Loader2,
  Trash2,
  Maximize2
} from 'lucide-react';
import { generateImage, generateVideo, imageToVideo, complexQuery } from '../services/gemini';

const StudioView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'text' | 'image' | 'video'>('text');
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleProcess = async () => {
    if (!prompt.trim()) return;
    setIsLoading(true);
    setResult(null);

    try {
      if (activeTab === 'text') {
        const res = await complexQuery(prompt);
        setResult({ type: 'text', content: res });
      } else if (activeTab === 'image') {
        const res = await generateImage(prompt, '16:9', '1K');
        setResult({ type: 'image', content: res });
      } else if (activeTab === 'video') {
        let res;
        if (uploadedImage) {
          res = await imageToVideo(prompt, uploadedImage);
        } else {
          res = await generateVideo(prompt);
        }
        setResult({ type: 'video', content: res });
      }
    } catch (err: any) {
      console.error(err);
      // Handle key issues by triggering the selection dialog again as per guidelines
      if (err?.message?.includes('Requested entity was not found')) {
        alert("Selected API key is invalid or not found. Please select a valid paid key.");
        if (window.aistudio?.openSelectKey) {
          await window.aistudio.openSelectKey();
        }
      } else {
        alert("Error generating content. Please check console.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="h-full flex flex-col bg-zinc-950 animate-in fade-in duration-500">
      <div className="flex-1 overflow-auto p-6 md:p-10 max-w-7xl mx-auto w-full grid grid-cols-1 lg:grid-cols-12 gap-10">

        {/* Input Controls */}
        <div className="lg:col-span-4 space-y-8">
          <div>
            <h2 className="text-3xl font-black text-white mb-2 flex items-center">
              <Sparkles className="w-8 h-8 mr-3 text-blue-500" />
              AI Studio
            </h2>
            <p className="text-zinc-500">Create production-ready assets with Gemini Pro & Veo.</p>
          </div>

          {/* Mode Selector */}
          <div className="bg-zinc-900 p-1.5 rounded-2xl flex border border-zinc-800">
            <ModeTab 
              active={activeTab === 'text'} 
              onClick={() => setActiveTab('text')} 
              icon={<FileText className="w-4 h-4" />} 
              label="Text" 
            />
            <ModeTab 
              active={activeTab === 'image'} 
              onClick={() => setActiveTab('image')} 
              icon={<ImageIcon className="w-4 h-4" />} 
              label="Image" 
            />
            <ModeTab 
              active={activeTab === 'video'} 
              onClick={() => setActiveTab('video')} 
              icon={<Video className="w-4 h-4" />} 
              label="Video" 
            />
          </div>

          <div className="space-y-4">
            <label className="text-xs font-bold text-zinc-500 uppercase tracking-widest px-1">Detailed Prompt</label>
            <textarea 
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder={`Describe your ${activeTab} in detail...`}
              className="w-full h-40 bg-zinc-900 border border-zinc-800 rounded-2xl p-4 text-zinc-200 outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 transition-all resize-none"
            />
          </div>

          {activeTab === 'video' && (
            <div className="space-y-4">
              <label className="text-xs font-bold text-zinc-500 uppercase tracking-widest px-1">Reference Image (Optional)</label>
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="w-full h-32 border-2 border-dashed border-zinc-800 rounded-2xl flex flex-col items-center justify-center cursor-pointer hover:border-blue-500/50 transition-colors group relative overflow-hidden"
              >
                {uploadedImage ? (
                  <>
                    <img src={uploadedImage} alt="Preview" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                      <Trash2 className="w-6 h-6 text-white" onClick={(e) => { e.stopPropagation(); setUploadedImage(null); }} />
                    </div>
                  </>
                ) : (
                  <>
                    <ImageIcon className="w-8 h-8 text-zinc-700 mb-2 group-hover:text-zinc-500 transition-colors" />
                    <span className="text-sm text-zinc-600">Upload starting frame</span>
                  </>
                )}
                <input type="file" ref={fileInputRef} hidden onChange={handleImageUpload} accept="image/*" />
              </div>
            </div>
          )}

          <button 
            onClick={handleProcess}
            disabled={isLoading || !prompt.trim()}
            className="w-full py-4 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-2xl font-black text-lg transition-all shadow-xl shadow-blue-500/20 flex items-center justify-center space-x-3"
          >
            {isLoading ? <Loader2 className="w-6 h-6 animate-spin" /> : <Sparkles className="w-6 h-6" />}
            <span>{isLoading ? 'Generating...' : 'Generate Magic'}</span>
          </button>
        </div>

        {/* Output Canvas */}
        <div className="lg:col-span-8">
          <div className="w-full h-full bg-zinc-900/50 border border-zinc-800 rounded-3xl overflow-hidden relative min-h-[500px] flex items-center justify-center">
            {!result && !isLoading && (
              <div className="text-center p-12">
                <div className="w-20 h-20 bg-zinc-800 rounded-full flex items-center justify-center mx-auto mb-6">
                  <Layers className="w-10 h-10 text-zinc-600" />
                </div>
                <h3 className="text-xl font-bold text-zinc-400 mb-2">Studio Preview</h3>
                <p className="text-zinc-600 max-w-sm mx-auto">Your generated assets will appear here. Start by writing a prompt on the left.</p>
              </div>
            )}

            {isLoading && (
              <div className="text-center">
                <Loader2 className="w-12 h-12 text-blue-500 animate-spin mx-auto mb-4" />
                <p className="text-blue-400 font-bold animate-pulse uppercase tracking-widest text-sm">Processing Neural Frames...</p>
              </div>
            )}

            {result && (
              <div className="w-full h-full flex flex-col p-4">
                <div className="flex-1 bg-zinc-950 rounded-2xl overflow-hidden flex items-center justify-center p-4">
                  {result.type === 'text' && (
                    <div className="w-full h-full overflow-auto prose prose-invert p-8 max-w-none">
                      <p className="whitespace-pre-wrap text-lg leading-relaxed">{result.content}</p>
                    </div>
                  )}
                  {result.type === 'image' && (
                    <img src={result.content} alt="Generated" className="max-w-full max-h-full object-contain rounded-lg shadow-2xl shadow-black/50" />
                  )}
                  {result.type === 'video' && (
                    <video src={result.content} controls autoPlay loop className="max-w-full max-h-full rounded-lg shadow-2xl shadow-black/50" />
                  )}
                </div>

                <div className="flex items-center justify-between mt-4 px-2">
                  <div className="flex items-center space-x-2">
                    <button className="p-2.5 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 rounded-xl transition-colors">
                      <Maximize2 className="w-5 h-5" />
                    </button>
                    <button className="p-2.5 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 rounded-xl transition-colors">
                      <RefreshCw className="w-5 h-5" />
                    </button>
                  </div>
                  <button className="flex items-center space-x-2 px-6 py-2.5 bg-zinc-100 hover:bg-white text-zinc-950 rounded-xl font-bold transition-all transform hover:scale-105">
                    <Download className="w-5 h-5" />
                    <span>Export</span>
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const ModeTab: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex-1 flex items-center justify-center space-x-2 py-2.5 rounded-xl transition-all font-bold text-sm ${active ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-zinc-300'}`}
  >
    {icon}
    <span>{label}</span>
  </button>
);

export default StudioView;
